import React, { useEffect, useState, useContext } from "react";
import Swal from "sweetalert2";
import { jsPDF } from "jspdf";
import { AuthContext } from "../context/authContext";

import { API } from "../Api/api.config";

// ===================== API ENDPOINTS =====================
const API_SELECT_USUARIOS  = API.SELECT;
const API_SELECT_CONTRATOS = API.SELECT_WHERE;
const API_INSERT_PAGO      = API.INSERT;
const API_ADEUDOS_GENERAR  = API.GENERAR_ADEUDOS;
const API_ADEUDOS_GET      = API.GET_ADEUDOS;
const API_UPDATE_ADEUDO    = API.UPDATE;
const API_INSERT_ADEUDO    = API.INSERT;

export default function RegistroPagos() {
    const { user } = useContext(AuthContext);
    const logoBase64 = "data:image/png;base64,";

    // ===================== STATE =====================
    const [usuarios, setUsuarios] = useState([]);
    const [contratos, setContratos] = useState([]);
    const [adeudos, setAdeudos] = useState([]);

    const [busquedaUsuario, setBusquedaUsuario] = useState("");
    const [usuarioSeleccionado, setUsuarioSeleccionado] = useState("");
    const [contratoSeleccionado, setContratoSeleccionado] = useState("");
    const [numContrato, setNumContrato] = useState("");

    const [anioPago, setAnioPago] = useState("");
    const [mesPago, setMesPago] = useState("");
    const [montoPago, setMontoPago] = useState("");
    const [metodoPago, setMetodoPago] = useState("");
    const [observaciones, setObservaciones] = useState("");

    // ===================== FECHA LOCAL =====================
    const getFechaLocal = () => {
        const now = new Date();
        const pad = (n) => n.toString().padStart(2, "0");
        return `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())} ${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;
    };

    // ===================== AUTO-GENERAR ADEUDO DEL AÑO ACTUAL =====================
    const generarAdeudoActual = async (id_usuario, id_contrato, adeudosExistentes) => {
        const anioActual = new Date().getFullYear();

        // Si ya existe el adeudo, NO insertar
        if (adeudosExistentes.includes(anioActual)) return;

        console.log(`⚠ Generando adeudo faltante del año ${anioActual}`);

        await fetch(API_INSERT_ADEUDO, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                table: "adeudos",
                data: {
                    id_usuario,
                    id_contrato,
                    anio: anioActual,
                    estado: "pendiente",
                    fecha_registro: getFechaLocal(),
                },
            }),
        });
    };

    // ===================== CARGAR USUARIOS =====================
    useEffect(() => {
        fetch(API_SELECT_USUARIOS, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                select: 'id_usuario, CONCAT_WS(" ", Nombre, Apellido_pat, Apellido_mat) AS Contratante',
                table: "usuarios",
                orderBy: "Nombre ASC",
            }),
        })
            .then((res) => res.json())
            .then((data) => {
                if (!data.error) setUsuarios(data);
            })
            .catch(() => Swal.fire("Error", "No se pudieron cargar los usuarios", "error"));
    }, []);

    // ===================== CARGAR CONTRATOS =====================
    useEffect(() => {
        if (!usuarioSeleccionado) return;

        fetch(API_SELECT_CONTRATOS, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                select: "id_contrato, num_contrato, Fecha_contrato",
                table: "contratos",
                column: "id_usuario",
                id: usuarioSeleccionado,
            }),
        })
            .then((res) => res.json())
            .then((data) => {
                if (!data.error) setContratos(data);
                else setContratos([]);
            })
            .catch(() => setContratos([]));
    }, [usuarioSeleccionado]);

    // ===================== GENERAR ADEUDOS + CARGAR ADEUDOS =====================
    useEffect(() => {
        if (!usuarioSeleccionado || !contratoSeleccionado) return;

        const contrato = contratos.find((c) => c.id_contrato == contratoSeleccionado);

        if (!contrato?.Fecha_contrato) return;

        // 1️⃣ Generar adeudos históricos según fecha del contrato (PHP)
        fetch(API_ADEUDOS_GENERAR, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                id_usuario: usuarioSeleccionado,
                id_contrato: contratoSeleccionado,
                fecha_contrato: contrato.Fecha_contrato,
            }),
        }).then(() => {
            // 2️⃣ Cargar adeudos
            fetch(API_ADEUDOS_GET, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    id_usuario: usuarioSeleccionado,
                    id_contrato: contratoSeleccionado,
                }),
            })
                .then((res) => res.json())
                .then(async (data) => {
                    setAdeudos(data);

                    // 3️⃣ AUTO-GENERAR ADEUDO DEL AÑO ACTUAL
                    const existentes = data.map((a) => Number(a.anio));
                    await generarAdeudoActual(usuarioSeleccionado, contratoSeleccionado, existentes);

                    // 4️⃣ Recargar con el adeudo actualizado
                    fetch(API_ADEUDOS_GET, {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({
                            id_usuario: usuarioSeleccionado,
                            id_contrato: contratoSeleccionado,
                        }),
                    })
                        .then((r) => r.json())
                        .then((finalData) => setAdeudos(finalData));
                });
        });
    }, [usuarioSeleccionado, contratoSeleccionado, contratos]);
    // ===================== LIMPIAR =====================
    const limpiar = () => {
        setBusquedaUsuario("");
        setUsuarioSeleccionado("");
        setContratoSeleccionado("");
        setNumContrato("");
        setAnioPago("");
        setMesPago("");
        setMontoPago("");
        setMetodoPago("");
        setObservaciones("");
        setAdeudos([]);
    };

    // ===================== GUARDAR EL PAGO =====================
    const guardarPago = async () => {
        if (!usuarioSeleccionado || !contratoSeleccionado) {
            Swal.fire("Error", "Usuario y contrato son obligatorios", "error");
            return;
        }

        if (!anioPago) {
            Swal.fire("Error", "Seleccione un año pendiente por pagar", "error");
            return;
        }

        // INSERTAR PAGO
        const payloadPago = {
            table: "pagos",
            data: {
                id_usuario: usuarioSeleccionado,
                id_contrato: contratoSeleccionado,
                anio_pago: anioPago,
                mes_pago: mesPago,
                monto_pago: montoPago,
                metodo_pago: metodoPago,
                observaciones,
                status: 1,
                fecha_registro: getFechaLocal(),
            },
        };

        const resPago = await fetch(API_INSERT_PAGO, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payloadPago),
        });

        const result = await resPago.json();

        if (!resPago.ok) {
            Swal.fire("Error", result?.error || "No se pudo registrar el pago", "error");
            return;
        }

        // ===================== MARCAR ADEUDO COMO PAGADO =====================
        const adeudo = adeudos.find((a) => a.anio == anioPago);

        if (adeudo) {
            await fetch(API_UPDATE_ADEUDO, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    table: "adeudos",
                    updates: { estado: "pagado" },
                    idField: "id_adeudo",
                    idValue: adeudo.id_adeudo,
                }),
            });
        }

        Swal.fire("Éxito", "Pago registrado correctamente", "success");

        generarPDF({
            usuario:
                usuarios.find((u) => u.id_usuario == usuarioSeleccionado)
                    ?.Contratante || "",
            numContrato,
            anioPago,
            mesPago,
            montoPago,
            metodoPago,
            observaciones,
        });

        limpiar();
    };

    // ===================== NÚMERO A LETRAS =====================
    function numeroALetras(num) {
        const unidades = [
            "", "UNO", "DOS", "TRES", "CUATRO", "CINCO",
            "SEIS", "SIETE", "OCHO", "NUEVE"
        ];

        const especiales = [
            "DIEZ", "ONCE", "DOCE", "TRECE", "CATORCE", "QUINCE",
            "DIECISÉIS", "DIECISIETE", "DIECIOCHO", "DIECINUEVE"
        ];

        const decenas = [
            "", "DIEZ", "VEINTE", "TREINTA", "CUARENTA",
            "CINCUENTA", "SESENTA", "SETENTA", "OCHENTA", "NOVENTA"
        ];

        const centenas = [
            "", "CIENTO", "DOSCIENTOS", "TRESCIENTOS", "CUATROCIENTOS",
            "QUINIENTOS", "SEISCIENTOS", "SETECIENTOS", "OCHOCIENTOS",
            "NOVECIENTOS"
        ];

        function convertir(n) {
            if (n === 0) return "";
            if (n < 10) return unidades[n];
            if (n < 20) return especiales[n - 10];
            if (n < 100) {
                if (n === 20) return "VEINTE";
                if (n < 30) return "VEINTI" + unidades[n - 20];
                return decenas[Math.floor(n / 10)] +
                    (n % 10 ? " Y " + unidades[n % 10] : "");
            }
            if (n < 1000) {
                if (n === 100) return "CIEN";
                return centenas[Math.floor(n / 100)] +
                    (n % 100 ? " " + convertir(n % 100) : "");
            }
            if (n < 1000000) {
                if (n === 1000) return "MIL";
                return convertir(Math.floor(n / 1000)) + " MIL" +
                    (n % 1000 ? " " + convertir(n % 1000) : "");
            }
            return convertir(Math.floor(n / 1000000)) + " MILLONES" +
                (n % 1000000 ? " " + convertir(n % 1000000) : "");
        }

        let partes = num.toString().split(".");
        let entero = parseInt(partes[0], 10);
        let decimales = partes[1] ? partes[1].padEnd(2, "0").slice(0, 2) : "00";

        let letraEntero = convertir(entero).trim();
        if (letraEntero === "") letraEntero = "CERO";

        return `${letraEntero} PESOS ${decimales}/100 M.N.`;
    }

    // ===================== PDF =====================
    const generarPDF = (info) => {
        const montoLetras = numeroALetras(parseInt(info.montoPago)) + " PESOS MXN";
        const doc = new jsPDF();
        const pageWidth = doc.internal.pageSize.getWidth();

        let y = 20;
        try {
            doc.addImage(logoBase64, "PNG", 15, 10, 30, 30);
        } catch (e) { }

        doc.setFont("helvetica", "bold");
        doc.setFontSize(17);
        doc.text("Comité del Agua Potable", pageWidth / 2, y, { align: "center" });

        y += 8;
        doc.setFont("helvetica", "normal");
        doc.setFontSize(11);
        doc.text("San Gaspar Tlahuelilpan, Metepec, Estado de México", pageWidth / 2, y, { align: "center" });

        y += 12;
        const fecha = new Date().toLocaleDateString("es-MX");
        doc.setFont("helvetica", "bold");
        doc.setFontSize(10);
        doc.text(`Fecha de expedición: ${fecha}`, pageWidth - 20, y, { align: "right" });

        y += 18;

        doc.setFontSize(14);
        doc.text("RECIBO DE PAGO POR ANUALIDAD", pageWidth / 2, y, { align: "center" });

        y += 5;
        doc.setLineWidth(0.5);
        doc.line(20, y, pageWidth - 20, y);

        y += 15;
        const datos = [
            ["Contratante", info.usuario],
            ["Número de contrato", info.numContrato],
            ["Año de pago", info.anioPago],
            ["Fecha de pago", fecha],
            ["Método de pago", info.metodoPago],
            ["Observaciones", info.observaciones || "Ninguna"],
        ];

        const leftX = 25;
        const rightX = 90;
        const lineHeight = 8;

        datos.forEach(([label, value]) => {
            doc.setFont("helvetica", "bold");
            doc.text(`${label}:`, leftX, y);
            doc.setFont("helvetica", "normal");
            doc.text(String(value), rightX, y);
            y += lineHeight;
        });

        y += 10;
        doc.setLineWidth(0.3);
        doc.rect(25, y - 6, pageWidth - 50, 20);

        const montoNumero = `$${parseFloat(info.montoPago).toLocaleString("es-MX", {
            minimumFractionDigits: 2,
        })}`;

        const montoLetra = numeroALetras(info.montoPago).toUpperCase();

        doc.setFont("helvetica", "bold");
        doc.setFontSize(13);
        doc.text(
            `MONTO PAGADO: ${montoNumero} (${montoLetra} MXN)`,
            pageWidth / 2,
            y + 4,
            { align: "center", maxWidth: pageWidth - 60 }
        );

        y += 40;
        doc.setLineWidth(0.3);
        doc.line(20, y, pageWidth - 20, y);

        y += 10;
        doc.setFontSize(9);
        doc.text(
            "El presente documento certifica el pago de anualidad del servicio de agua potable.",
            pageWidth / 2,
            y,
            { align: "center" }
        );
        y += 5;
        doc.text(
            "Emitido oficialmente por el Comité del Agua Potable de San Gaspar Tlahuelilpan, Metepec. Guárdese como comprobante.",
            pageWidth / 2,
            y,
            { align: "center" }
        );

        doc.save(`Recibo_Anualidad_${info.anioPago}_${info.usuario}_${info.numContrato}.pdf`);
        window.open(doc.output("bloburl"), "_blank");
    };

    // ===================== PERMISOS =====================
    if (!["admin", "caja"].includes(user?.rol)) {
        return <h2 style={{ textAlign: "center" }}>Acceso denegado</h2>;
    }

    // ===================== RENDER =====================
    return (
        <div style={containerStyle}>
            <h2 style={{ textAlign: "center" }}>Registro de Pago Por Anualidad</h2>

            <form
                onSubmit={(e) => {
                    e.preventDefault();
                    guardarPago();
                }}
                style={formStyle}
            >
                <input
                    placeholder="Buscar contratante"
                    value={busquedaUsuario}
                    onChange={(e) => setBusquedaUsuario(e.target.value)}
                    style={inputStyle}
                />

                <select
                    required
                    value={usuarioSeleccionado}
                    onChange={(e) => setUsuarioSeleccionado(e.target.value)}
                    style={inputStyle}
                >
                    <option value="">SELECCIONE USUARIO</option>
                    {usuarios
                        .filter((u) =>
                            u.Contratante.toLowerCase().includes(
                                busquedaUsuario.toLowerCase()
                            )
                        )
                        .map((u) => (
                            <option key={u.id_usuario} value={u.id_usuario}>
                                {u.Contratante}
                            </option>
                        ))}
                </select>

                <select
                    required
                    value={contratoSeleccionado}
                    onChange={(e) => {
                        setContratoSeleccionado(e.target.value);
                        const c = contratos.find(
                            (x) => x.id_contrato == e.target.value
                        );
                        setNumContrato(c?.num_contrato || "");
                    }}
                    style={inputStyle}
                >
                    <option value="">SELECCIONE CONTRATO</option>
                    {contratos.map((c) => (
                        <option key={c.id_contrato} value={c.id_contrato}>
                            {c.num_contrato}
                        </option>
                    ))}
                </select>

                {/* SELECT AÑOS PENDIENTES */}
                <select
                    required
                    value={anioPago}
                    onChange={(e) => setAnioPago(e.target.value)}
                    style={inputStyle}
                >
                    <option value="">Seleccione año pendiente</option>

                    {adeudos
                        .filter((a) => a.estado === "pendiente")
                        .map((a) => (
                            <option key={a.id_adeudo} value={a.anio}>
                                {a.anio}
                            </option>
                        ))}
                </select>

                <input
                    type="number"
                    placeholder="Monto"
                    value={montoPago}
                    onChange={(e) => setMontoPago(e.target.value)}
                    style={inputStyle}
                />

                <select
                    value={metodoPago}
                    onChange={(e) => setMetodoPago(e.target.value)}
                    style={inputStyle}
                >
                    <option value="">Método de pago</option>
                    {["EFECTIVO", "TRANSFERENCIA", "TARJETA", "CONDONACIÓN"].map((m) => (
                        <option key={m}>{m}</option>
                    ))}
                </select>

                <input
                    placeholder="Observaciones"
                    value={observaciones}
                    onChange={(e) => setObservaciones(e.target.value)}
                    style={inputStyle}
                />

                <button style={buttonStyle}>Registrar Pago</button>
            </form>
        </div>
    );
}

/* ===================== ESTILOS ===================== */

const containerStyle = {
    maxWidth: 600,
    margin: "40px auto",
    padding: 20,
    background: "#f9f9f9",
    borderRadius: 10,
};

const formStyle = {
    display: "flex",
    flexDirection: "column",
    gap: 15,
};

const inputStyle = {
    padding: 10,
    borderRadius: 6,
    border: "1px solid #ccc",
};

const buttonStyle = {
    padding: 12,
    background: "#0077b6",
    color: "#fff",
    border: "none",
    borderRadius: 6,
};
